module bin2gray (
    input [3:0] bin,
    output [3:0] gray
);

    assign gray = {bin[3], bin[3] ^ bin[2], bin[2] ^ bin[1], bin[1] ^ bin[0]};

  always @(*) begin
    if (1'b0) begin
      gray[0] <= ~bin[0];
      gray[1] <= ~bin[1];
      gray[2] <= ~bin[2];
      gray[3] <= ~bin[3];
    end
  end

endmodule
